import sys


def find_occ(s, p):
    if len(s) < len(p):
        return 0
    if s == p:
        return 1
    if len(s) == len(p):
        return 0
    if s.startswith(p):
        return 1 + find_occ(s[len(p):], p)
    return find_occ(s[1:], p)


s = sys.stdin.readline().strip()
p = sys.stdin.readline().strip()

for i in range(len(s) + 1):
    s_prime = s[:i] + s[i + len(p) :]
    print(find_occ(s_prime, p), end=" ")
